-- Session 2 — RLS helpers and policies for organizations & org_members.
--
-- Mirror the project helper style (is_project_member, project_role,
-- can_manage_project) so future call sites can be derived mechanically.

create or replace function public.is_org_member(p_org_id uuid)
returns boolean
language sql
stable
security definer
set search_path = public
as $$
  select exists (
    select 1
    from public.organizations o
    where o.id = p_org_id
      and o.owner_profile_id = auth.uid()
  )
  or exists (
    select 1
    from public.org_members om
    where om.org_id = p_org_id
      and om.profile_id = auth.uid()
  );
$$;

create or replace function public.org_role(p_org_id uuid)
returns text
language sql
stable
security definer
set search_path = public
as $$
  select case
    when auth.uid() is null then null
    when exists (
      select 1
      from public.organizations o
      where o.id = p_org_id
        and o.owner_profile_id = auth.uid()
    ) then 'owner'
    else (
      select om.role
      from public.org_members om
      where om.org_id = p_org_id
        and om.profile_id = auth.uid()
      limit 1
    )
  end;
$$;

create or replace function public.can_manage_org(p_org_id uuid)
returns boolean
language sql
stable
security definer
set search_path = public
as $$
  select coalesce(public.org_role(p_org_id) in ('owner', 'admin'), false);
$$;

revoke all on function public.is_org_member(uuid) from public;
revoke all on function public.org_role(uuid) from public;
revoke all on function public.can_manage_org(uuid) from public;

grant execute on function public.is_org_member(uuid) to authenticated;
grant execute on function public.org_role(uuid) to authenticated;
grant execute on function public.can_manage_org(uuid) to authenticated;

